func TestEnumAliasToPrompt(t *testing.T) {
	t.Run("NewFromString_You_are_a_helpful_assistant", func(t *testing.T) {
		t.Parallel()
		val, err := NewAliasToPromptFromString("You are a helpful assistant")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, AliasToPrompt("You are a helpful assistant"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewAliasToPromptFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewAliasToPromptFromString("You are a helpful assistant")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

